import{_ as e,o,c as r,a2 as a}from"./chunks/framework.CKCxdkvf.js";const h=JSON.parse('{"title":"Agency mission imagery — build-time source map (ADR-046)","description":"","frontmatter":{},"headers":[],"relativePath":"research/agency-mission-image-sources.md","filePath":"research/agency-mission-image-sources.md"}'),s={name:"research/agency-mission-image-sources.md"};function n(i,t,d,c,l,g){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="agency-mission-imagery-—-build-time-source-map-adr-046" tabindex="-1">Agency mission imagery — build-time source map (ADR-046) <a class="header-anchor" href="#agency-mission-imagery-—-build-time-source-map-adr-046" aria-label="Permalink to &quot;Agency mission imagery — build-time source map (ADR-046)&quot;">​</a></h1><p>Evidence-backed notes for <strong>where each operator publishes mission stills</strong>, what Orrery can use <strong>anonymously at build time</strong> (CI / <code>npm run fetch-assets</code>), and <strong>licensing</strong>. Canonical mission ids and agency strings match <code>static/data/missions/index.json</code> plus legacy fetch ids <code>mars2</code>, <code>mars6</code> (Soviet Mars programme, same editorial class as <code>mars3</code>).</p><p><strong>Gate:</strong> Implementation prefers <strong>(A)</strong> stable direct image URLs or JSON search APIs, or <strong>(B)</strong> <strong>curated Wikimedia Commons</strong> filenames verified in-repo, then <strong>NASA Images API</strong> as a broad fallback with a <strong>strict credit filter</strong> (extended only for named missions; see ADR-046).</p><hr><h2 id="nasa" tabindex="-1">NASA <a class="header-anchor" href="#nasa" aria-label="Permalink to &quot;NASA&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Primary</strong></td><td><a href="https://images.nasa.gov/docs/images.nasa.gov_api_docs.html" target="_blank" rel="noreferrer">NASA Images API</a> — anonymous <code>GET</code>, JSON, preview <code>href</code> links suitable for build-time download.</td></tr><tr><td><strong>Fallbacks</strong></td><td>Wikimedia Commons for catalogue rows where API credits are thin; curated lists in <code>scripts/fetch-assets.ts</code>.</td></tr><tr><td><strong>Feasibility</strong></td><td><strong>Go</strong> — already integrated.</td></tr><tr><td><strong>License / credit</strong></td><td>NASA media usage guidelines; <code>secondary_creator</code> filtered in code for US NASA–family strings.</td></tr></tbody></table><hr><h2 id="roscosmos-incl-soviet-lunar-mars-heritage" tabindex="-1">ROSCOSMOS (incl. Soviet lunar / Mars heritage) <a class="header-anchor" href="#roscosmos-incl-soviet-lunar-mars-heritage" aria-label="Permalink to &quot;ROSCOSMOS (incl. Soviet lunar / Mars heritage)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Primary operator</strong></td><td><a href="https://www.roscosmos.ru/en/" target="_blank" rel="noreferrer">Roscosmos EN</a> — press releases and galleries; <strong>no</strong> stable public JSON image search comparable to NASA Images API found for machine bulk download.</td></tr><tr><td><strong>National wires</strong></td><td>TASS and partner outlets often mirror handouts; URLs are <strong>HTML / CDN–opaque</strong>, not suitable as deterministic CI fetches.</td></tr><tr><td><strong>Feasibility</strong></td><td><strong>No-go</strong> for automated anonymous primary fetch without scraping or brittle HTML parsing (<strong>red-list</strong>).</td></tr><tr><td><strong>Implementation</strong></td><td><strong>Curated Commons</strong> (<code>mars3</code>, <code>luna9</code>, <code>luna17</code>, <code>luna24</code>, legacy <code>mars2</code> / <code>mars6</code>) as editorial primary; NASA API <strong>last</strong>, with queries tuned to <strong>historic cooperation / PIA</strong> assets where credits remain honest.</td></tr></tbody></table><hr><h2 id="esa" tabindex="-1">ESA <a class="header-anchor" href="#esa" aria-label="Permalink to &quot;ESA&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Primary operator</strong></td><td><a href="https://www.esa.int/Science_Exploration/Space_Science" target="_blank" rel="noreferrer">ESA Science &amp; Exploration images</a>, <a href="https://photolibrary.esa.int/" target="_blank" rel="noreferrer">Photolibrary</a> — browse-first web UI; image pages are <strong>HTML</strong> with assets behind site mechanics and session/cookie banners.</td></tr><tr><td><strong>Machine API</strong></td><td>No small, documented, <strong>anonymous</strong> JSON endpoint equivalent to NASA’s <code>/search</code> was identified for <strong>bulk</strong> mission stills suitable for this repo’s fetch script.</td></tr><tr><td><strong>Spike outcome</strong></td><td><strong>No-go</strong> for a dedicated <code>fetchEsaImageUrls()</code> adapter in CI without auth, headless browsing, or contractual API access.</td></tr><tr><td><strong>Implementation</strong></td><td><strong>Curated Commons</strong> for <code>mars-express</code> (hero + gallery). NASA fallback allowed only when <code>secondary_creator</code> matches extended allowlist for <strong><code>mars-express</code></strong> (partner / ESA-credited NASA archive entries).</td></tr></tbody></table><hr><h2 id="cnsa" tabindex="-1">CNSA <a class="header-anchor" href="#cnsa" aria-label="Permalink to &quot;CNSA&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Primary</strong></td><td>CNSA / state press imagery is typically distributed via <strong>Chinese state media</strong> and exhibition photo sets; no assumed <strong>stable anonymous JSON</strong> image API for mission press packs.</td></tr><tr><td><strong>Feasibility</strong></td><td><strong>No-go</strong> for automated primary HTTP adapter.</td></tr><tr><td><strong>Implementation</strong></td><td><strong>Curated Commons</strong> for <code>tianwen1</code>, <code>change4</code>, <code>change5</code>, <code>change6</code>; NASA API <strong>last</strong> and <strong>query-tuned</strong> (often thin); do not prefer NASA over Commons for these ids.</td></tr></tbody></table><hr><h2 id="isro" tabindex="-1">ISRO <a class="header-anchor" href="#isro" aria-label="Permalink to &quot;ISRO&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Primary</strong></td><td>ISRO press gallery / social distribution; public <strong>Bhoonidhi</strong>-class portals target <strong>Earth observation products</strong>, not Mars/Moon press galleries — wrong domain for hero sourcing.</td></tr><tr><td><strong>Feasibility</strong></td><td><strong>No-go</strong> for EO API as mission gallery source.</td></tr><tr><td><strong>Implementation</strong></td><td><strong>Curated Commons</strong> for <code>mangalyaan</code>, <code>chandrayaan1</code>, <code>chandrayaan3</code>; NASA fallback only with honest credits.</td></tr></tbody></table><hr><h2 id="jaxa" tabindex="-1">JAXA <a class="header-anchor" href="#jaxa" aria-label="Permalink to &quot;JAXA&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Primary</strong></td><td><a href="https://jaxa.repo.nii.ac.jp/" target="_blank" rel="noreferrer">JAXA Digital Archives</a>, mission pages, SLIM/MMX press kits — <strong>browse-first</strong> or repository metadata; not a single obvious anonymous <strong>image search JSON</strong> for scripted gallery fill.</td></tr><tr><td><strong>Spike outcome</strong></td><td><strong>No-go</strong> for a minimal anonymous adapter without deeper integration or scraping.</td></tr><tr><td><strong>Implementation</strong></td><td><strong>Curated Commons</strong> for <code>slim</code>, <code>mmx</code>. NASA fallback with <strong><code>mmx</code> / <code>slim</code>-scoped</strong> credit allowlist (<code>jaxa</code>, <code>isas</code>, etc.) where editorially appropriate.</td></tr></tbody></table><hr><h2 id="uaesa-mbrsc-hope" tabindex="-1">UAESA / MBRSC (Hope) <a class="header-anchor" href="#uaesa-mbrsc-hope" aria-label="Permalink to &quot;UAESA / MBRSC (Hope)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Primary</strong></td><td><a href="https://www.emiratesmarsmission.ae/" target="_blank" rel="noreferrer">Emirates Mars Mission</a> — official imagery; many pages are <strong>marketing HTML</strong> without stable direct JPEG URLs for CI.</td></tr><tr><td><strong>Spike outcome</strong></td><td><strong>No-go</strong> for non-scraping automated primary fetch; verify <strong>Terms</strong> before any future HTTP adapter.</td></tr><tr><td><strong>Implementation</strong></td><td><strong>Curated Commons</strong> + NASA fallback with query <code>emirates mars mission hope spacecraft</code>; allowlist may include <code>mbrsc</code>, <code>uae</code>, <code>emirates mars</code> for <strong><code>hope-probe</code></strong> only.</td></tr></tbody></table><hr><h2 id="spacex" tabindex="-1">SpaceX <a class="header-anchor" href="#spacex" aria-label="Permalink to &quot;SpaceX&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Primary</strong></td><td>Official site / X / <strong>Flickr history</strong> — URL patterns and CDNs change; bulk download risks <strong>ToS</strong> issues.</td></tr><tr><td><strong>Feasibility</strong></td><td><strong>No-go</strong> for scraping <code>spacex.com</code>.</td></tr><tr><td><strong>Implementation</strong></td><td><strong>Curated Commons</strong> for <code>starship-demo</code>, <code>starship-mars-crew</code>; NASA fallback only for clearly <strong>NASA–SpaceX cooperation</strong> results (credit filter).</td></tr></tbody></table><hr><h2 id="blue-origin" tabindex="-1">Blue Origin <a class="header-anchor" href="#blue-origin" aria-label="Permalink to &quot;Blue Origin&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Primary</strong></td><td>Corporate press pages; no stable anonymous image API assumed.</td></tr><tr><td><strong>Implementation</strong></td><td><strong>Curated Commons</strong> + tight NASA query for <code>blue-moon-mk1</code>.</td></tr></tbody></table><hr><h2 id="inspiration-mars" tabindex="-1">Inspiration Mars <a class="header-anchor" href="#inspiration-mars" aria-label="Permalink to &quot;Inspiration Mars&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Primary</strong></td><td>Concept / foundation imagery — mixed rights; prefer <strong>Commons</strong> files with clear licenses aligned to mission <code>credit</code> in base JSON.</td></tr><tr><td><strong>Implementation</strong></td><td><strong>Curated Commons</strong>; avoid misleading NASA-only Orion imagery unless copy ties the foundation concept to NASA hardware <strong>and</strong> credits remain accurate.</td></tr></tbody></table><hr><h2 id="pipeline-order-implemented" tabindex="-1">Pipeline order (implemented) <a class="header-anchor" href="#pipeline-order-implemented" aria-label="Permalink to &quot;Pipeline order (implemented)&quot;">​</a></h2><ol><li>Optional <strong>Commons hero</strong> (<code>commonsCoverFirst</code>) → <code>01.jpg</code> + legacy card cover.</li><li><strong><code>fetchAgencyPrimaryImageUrls</code></strong> — returns NASA API preview URLs <strong>only</strong> when <code>normalizeAgency(agency) === &#39;NASA&#39;</code>; otherwise <code>[]</code> (agency “primary” is the curated Commons pass).</li><li><strong>Wikimedia</strong> fallback + gallery lists.</li><li><strong>NASA Images API</strong> fill for remaining slots (non-NASA agencies), with <strong>mission-scoped</strong> credit extensions documented in ADR-046.</li></ol><hr><h2 id="commons-filename-drift" tabindex="-1">Commons filename drift <a class="header-anchor" href="#commons-filename-drift" aria-label="Permalink to &quot;Commons filename drift&quot;">​</a></h2><p>Wikimedia Commons <strong>renames or deletes</strong> files over time. Curated lists in <code>scripts/fetch-assets.ts</code> are <strong>spot-checked</strong> with <code>Special:FilePath</code> during maintenance; broken <code>commonsCoverFirst</code> entries skip the hero and NASA search fills <code>01.jpg</code> with a <strong>noisier</strong> default.</p><p><strong>Maintenance recipe:</strong> for each curated Commons title (<code>commonsCoverFirst</code> / <code>commonsHeroFirst</code> / <code>WIKIMEDIA_ISS_FALLBACK</code> / <code>wikimediaFallback</code> / gallery arrays in <code>scripts/fetch-assets.ts</code>), <code>GET</code><br><code>https://commons.wikimedia.org/wiki/Special:FilePath/{urlencoded_title}?width=800</code><br> with a descriptive <code>User-Agent</code> and ≥300–500 ms between checks; on <strong>404</strong>, search <code>action=query&amp;list=search&amp;srnamespace=6</code> on Commons, skip <code>.pdf</code>/<code>.webm</code>/unrelated hits, then re-verify the replacement.</p><p><strong>Audits:</strong> <strong>2026-05-07</strong> — mission <code>MISSION_IMAGE_QUERIES</code> + <code>WIKIMEDIA_MISSION_*</code>. <strong>2026-05-07</strong> — ISS module heroes + cupola/canadarm gallery lists; earth-object panel heroes (Hubble, Chandra, XMM, JWST, Galileo nav, Ceres, Halley, 67P, …); small-body gallery strings; moon-site <code>change3</code> Wikimedia list.</p><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><ul><li><strong>2026-05-06</strong> — Initial map + ESA / JAXA / UAESA spike <strong>no-go</strong> for CI-grade HTTP adapters; Commons + NASA fallback strategy locked for implementation.</li></ul>',43)])])}const p=e(s,[["render",n]]);export{h as __pageData,p as default};
